// Code generated by Prompty emitter; DO NOT EDIT.

#![allow(unused_imports, dead_code, non_camel_case_types, unused_variables, clippy::all)]

use prompty::model::SessionTrace;
use prompty::model::context::{LoadContext, SaveContext};

#[test]
fn test_session_trace_load_json() {
    let json = r####"
{
  "version": "1",
  "runtime": "typescript",
  "promptyVersion": "2.0.0",
  "sessionId": "sess_abc123"
}
"####;
    let ctx = LoadContext::default();
    let result = SessionTrace::from_json(json, &ctx);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert_eq!(instance.version, "1");
    assert!(instance.runtime.is_some(), "Expected runtime to be Some");
    assert_eq!(instance.runtime.as_ref().unwrap(), &"typescript");
    assert!(instance.prompty_version.is_some(), "Expected prompty_version to be Some");
    assert_eq!(instance.prompty_version.as_ref().unwrap(), &"2.0.0");
    assert!(instance.session_id.is_some(), "Expected session_id to be Some");
    assert_eq!(instance.session_id.as_ref().unwrap(), &"sess_abc123");
}

#[test]
fn test_session_trace_load_yaml() {
    let yaml = r####"
version: "1"
runtime: typescript
promptyVersion: 2.0.0
sessionId: sess_abc123

"####;
    let ctx = LoadContext::default();
    let result = SessionTrace::from_yaml(yaml, &ctx);
    assert!(result.is_ok(), "Failed to load from YAML: {:?}", result.err());
    let instance = result.unwrap();
    assert_eq!(instance.version, "1");
    assert!(instance.runtime.is_some(), "Expected runtime to be Some");
    assert!(instance.prompty_version.is_some(), "Expected prompty_version to be Some");
    assert!(instance.session_id.is_some(), "Expected session_id to be Some");
}

#[test]
fn test_session_trace_roundtrip() {
    let json = r####"
{
  "version": "1",
  "runtime": "typescript",
  "promptyVersion": "2.0.0",
  "sessionId": "sess_abc123"
}
"####;
    let load_ctx = LoadContext::default();
    let result = SessionTrace::from_json(json, &load_ctx);
    assert!(result.is_ok(), "Failed to load: {:?}", result.err());
    let instance = result.unwrap();
    let save_ctx = SaveContext::default();
    let json_output = instance.to_json(&save_ctx);
    assert!(json_output.is_ok(), "Failed to serialize to JSON: {:?}", json_output.err());
}
